import{_ as a,c as e,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"セキュリティ: APIキー保護の仕組み | opencode-mystatus","description":"opencode-mystatusのセキュリティ設計を学びます。読み取り専用ファイルアクセス、APIキーマスキング、公式API呼び出しの仕組みを解説。","frontmatter":{"title":"セキュリティ: APIキー保護の仕組み | opencode-mystatus","sidebarTitle":"セキュリティ","subtitle":"セキュリティとプライバシー：ローカルファイルアクセス、APIマスキング、公式インターフェース","description":"opencode-mystatusのセキュリティ設計を学びます。読み取り専用ファイルアクセス、APIキーマスキング、公式API呼び出しの仕組みを解説。","tags":["セキュリティ","プライバシー","FAQ"],"prerequisite":[],"order":2},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/faq/security/index.md","filePath":"ja/vbgate/opencode-mystatus/faq/security/index.md"}'),d={name:"ja/vbgate/opencode-mystatus/faq/security/index.md"};function i(l,t,r,n,c,h){return o(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="セキュリティとプライバシー-ローカルファイルアクセス、apiマスキング、公式インターフェース" tabindex="-1">セキュリティとプライバシー：ローカルファイルアクセス、APIマスキング、公式インターフェース <a class="header-anchor" href="#セキュリティとプライバシー-ローカルファイルアクセス、apiマスキング、公式インターフェース" aria-label="Permalink to &quot;セキュリティとプライバシー：ローカルファイルアクセス、APIマスキング、公式インターフェース&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">ローカルファースト原則</p><p>opencode-mystatusは「読み取り専用ローカルファイル + 公式API直接クエリ」の原則に従い、すべての機密操作はユーザーのマシン上で完了し、第三者サーバーを経由しません。</p></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p>プラグインのセキュリティデザインは3つの核心原則に基づいています：</p><ol><li><strong>読み取り専用原則</strong>：ローカル認証ファイルのみを読み取り、書き込みや修正を行わない</li><li><strong>公式インターフェース</strong>：各プラットフォームの公式APIのみを呼び出し、第三者サービスを使用しない</li><li><strong>データマスキング</strong>：表示時に機密情報（APIキーなど）を自動的に隠す</li></ol><h2 id="ローカルファイルアクセス-読み取り専用" tabindex="-1">ローカルファイルアクセス（読み取り専用） <a class="header-anchor" href="#ローカルファイルアクセス-読み取り専用" aria-label="Permalink to &quot;ローカルファイルアクセス（読み取り専用）&quot;">​</a></h2><h3 id="プラグインが読み取るファイル" tabindex="-1">プラグインが読み取るファイル <a class="header-anchor" href="#プラグインが読み取るファイル" aria-label="Permalink to &quot;プラグインが読み取るファイル&quot;">​</a></h3><p>プラグインは2つのローカル設定ファイルのみを読み取り、すべて<strong>読み取り専用</strong>です：</p><table tabindex="0"><thead><tr><th>ファイルパス</th><th>用途</th><th>ソースコードの場所</th></tr></thead><tbody><tr><td><code>~/.local/share/opencode/auth.json</code></td><td>OpenCode公式認証ストレージ</td><td><code>mystatus.ts:35</code></td></tr><tr><td><code>~/.config/opencode/antigravity-accounts.json</code></td><td>Antigravityプラグインアカウントストレージ</td><td><code>google.ts</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">ファイルを修正しない</p><p>ソースコードでは <code>readFile</code> 関数のみを使用してファイルを読み取り、<code>writeFile</code> やその他の修正操作は一切行いません。これにより、プラグインが誤って設定を上書きすることがなくなります。</p></div><h2 id="apiキーの自動マスキング" tabindex="-1">APIキーの自動マスキング <a class="header-anchor" href="#apiキーの自動マスキング" aria-label="Permalink to &quot;APIキーの自動マスキング&quot;">​</a></h2><h3 id="マスキングとは" tabindex="-1">マスキングとは？ <a class="header-anchor" href="#マスキングとは" aria-label="Permalink to &quot;マスキングとは？&quot;">​</a></h3><p>マスキング（Masking）とは、機密情報を表示する際、一部の文字のみを表示し、重要部分を隠すことです。</p><p>例：Zhipu AI APIキーが以下の場合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sk-9c89abc1234567890abcdefAQVM</span></span></code></pre></div><p>マスキング後の表示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sk-9c8****fAQVM</span></span></code></pre></div><h3 id="マスキングルール" tabindex="-1">マスキングルール <a class="header-anchor" href="#マスキングルール" aria-label="Permalink to &quot;マスキングルール&quot;">​</a></h3><p>プラグインは <code>maskString</code> 関数を使用してすべての機密情報を処理します：</p><ul><li>デフォルトで前4桁と後4桁を表示</li><li>中間部分を <code>****</code> に置換</li><li>文字列が短すぎる（≤8桁）場合、そのまま返す</li></ul><h2 id="公式インターフェース呼び出し" tabindex="-1">公式インターフェース呼び出し <a class="header-anchor" href="#公式インターフェース呼び出し" aria-label="Permalink to &quot;公式インターフェース呼び出し&quot;">​</a></h2><h3 id="プラグインが呼び出すapi" tabindex="-1">プラグインが呼び出すAPI <a class="header-anchor" href="#プラグインが呼び出すapi" aria-label="Permalink to &quot;プラグインが呼び出すAPI&quot;">​</a></h3><p>プラグインは各プラットフォームの<strong>公式API</strong>のみを呼び出し、第三者サーバーを経由しません：</p><table tabindex="0"><thead><tr><th>プラットフォーム</th><th>APIエンドポイント</th><th>用途</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>https://chatgpt.com/backend-api/wham/usage</code></td><td>クォータクエリ</td></tr><tr><td>Zhipu AI</td><td><code>https://bigmodel.cn/api/monitor/usage/quota/limit</code></td><td>Tokenクォータクエリ</td></tr><tr><td>GitHub Copilot</td><td><code>https://api.github.com/copilot_internal/user</code></td><td>クォータクエリ</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">公式APIのセキュリティ</p><p>これらのAPIエンドポイントはすべて各プラットフォームの公式インターフェースで、HTTPS暗号化送信を使用します。プラグインは「クライアント」としてリクエストを送信するだけで、データの保存や転送を行いません。</p></div><h2 id="セキュリティとプライバシーに関するq-a" tabindex="-1">セキュリティとプライバシーに関するQ&amp;A <a class="header-anchor" href="#セキュリティとプライバシーに関するq-a" aria-label="Permalink to &quot;セキュリティとプライバシーに関するQ&amp;A&quot;">​</a></h2><details class="details custom-block"><summary>プラグインは私のAPIキーを盗むのですか？</summary><p>盗みません。プラグインはAPIキーを使用して公式APIにリクエストを送信するだけで、第三者サーバーに保存や転送を行いません。すべてのコードはオープンソースで、監査できます。</p></details><details class="details custom-block"><summary>なぜマスキングされたAPIキーを表示するのですか？</summary><p>プライバシー保護のためです。クエリ結果のスクリーンショットを共有しても、完全なAPIキーは漏洩しません。マスキング後は前後4桁のみが表示され、中間の重要部分は隠されています。</p></details><details class="details custom-block"><summary>プラグインは私の設定ファイルを修正しますか？</summary><p>修正しません。プラグインは <code>readFile</code> のみを使用してファイルを読み取り、書き込み操作を一切行いません。設定ファイルの形式が間違っている場合、プラグインはエラーメッセージを返し、修正や上書きを試みません。</p></details><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><ul><li><strong>読み取り専用原則</strong>：プラグインはローカル認証ファイルのみを読み取り、一切修正を行わない</li><li><strong>APIマスキング</strong>：表示時にAPIキーの重要部分を自動的に隠す</li><li><strong>公式インターフェース</strong>：各プラットフォームの公式APIのみを呼び出し、第三者サービスを使用しない</li><li><strong>オープンソース透明性</strong>：すべてのコードはオープンソースで、セキュリティメカニズムを監査できます</li></ul><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>認証ファイル読み取り</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts#L38-L40" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>38-40</td></tr><tr><td>APIマスキング関数</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/utils.ts#L130-L135" target="_blank" rel="noreferrer"><code>plugin/lib/utils.ts</code></a></td><td>130-135</td></tr></tbody></table></details>',34)])])}const b=a(d,[["render",i]]);export{u as __pageData,b as default};
